=<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f4f6fa; margin: 0; padding: 20px; }
    .container { max-width: 640px; margin: 0 auto; }
    .header { background: linear-gradient(135deg, #1D5016 0%, #367C2B 100%); border-radius: 14px 14px 0 0; padding: 28px 32px; text-align: center; }
    .header h1 { color: #FFDE00; font-size: 22px; font-weight: 800; margin: 0; letter-spacing: -0.5px; }
    .header p { color: rgba(255,255,255,0.7); font-size: 13px; margin: 6px 0 0; }
    .body { background: #fff; padding: 28px 32px; border-radius: 0 0 14px 14px; border: 1px solid #e2e8f0; border-top: none; }
    .narrativa { background: #f0f7ee; border-left: 4px solid #367C2B; border-radius: 0 10px 10px 0; padding: 16px 20px; margin-bottom: 24px; font-size: 14px; line-height: 1.7; color: #1a3a14; }
    .narrativa-label { font-size: 10px; font-weight: 700; color: #367C2B; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 8px; }
    .kpis { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; margin-bottom: 24px; }
    .kpi { background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 10px; padding: 14px 16px; text-align: center; }
    .kpi-valor { font-size: 28px; font-weight: 800; color: #0f172a; line-height: 1; }
    .kpi-label { font-size: 11px; color: #64748b; margin-top: 4px; font-weight: 500; }
    .section-title { font-size: 13px; font-weight: 700; color: #0f172a; margin: 20px 0 10px; text-transform: uppercase; letter-spacing: 0.04em; }
    .atendente-row { display: flex; align-items: center; justify-content: space-between; padding: 8px 12px; border-radius: 8px; margin-bottom: 4px; background: #f8fafc; }
    .atendente-nome { font-size: 13px; color: #334155; font-weight: 500; }
    .atendente-qtd { font-size: 13px; font-weight: 800; color: #367C2B; }
    .categoria-row { display: flex; align-items: center; justify-content: space-between; padding: 6px 12px; border-radius: 6px; margin-bottom: 3px; }
    .categoria-nome { font-size: 12px; color: #475569; }
    .categoria-qtd { font-size: 12px; font-weight: 700; color: #64748b; }
    .sla-bar { height: 8px; border-radius: 4px; background: #e2e8f0; margin-top: 8px; overflow: hidden; }
    .sla-fill { height: 100%; border-radius: 4px; }
    .footer { text-align: center; padding: 16px; font-size: 11px; color: #94a3b8; }
    .badge { display: inline-block; padding: 2px 8px; border-radius: 20px; font-size: 11px; font-weight: 700; }
    .badge-green { background: #f0fdf4; color: #16a34a; }
    .badge-red { background: #fef2f2; color: #ef4444; }
    .badge-amber { background: #fffbeb; color: #d97706; }
  </style>
</head>
<body>
<div class="container">

  <!-- Header -->
  <div class="header">
    <h1>JOHN DEERE — Relatório TI</h1>
    <p>{{ $now.setLocale('pt').toFormat('cccc, dd \"de\" MMMM \"de\" yyyy') }}</p>
  </div>

  <div class="body">

    <!-- Narrativa IA -->
    {{ $('IA — Buscar Narrativa').item.json.sucesso ? '<div class="narrativa"><div class="narrativa-label">✨ Análise por Inteligência Artificial</div>' + $('IA — Buscar Narrativa').item.json.narrativa.replace(/\n/g, '<br>') + '</div>' : '' }}

    <!-- KPIs principais -->
    <div class="kpis">
      <div class="kpi">
        <div class="kpi-valor" style="color: #ef4444;">{{ $('Webhook — Recebe do Backend').item.json.resumo?.abertos ?? 0 }}</div>
        <div class="kpi-label">Abertos</div>
      </div>
      <div class="kpi">
        <div class="kpi-valor" style="color: #16a34a;">{{ $('Webhook — Recebe do Backend').item.json.resumo?.solucionadosHoje ?? 0 }}</div>
        <div class="kpi-label">Solucionados Hoje</div>
      </div>
      <div class="kpi">
        <div class="kpi-valor" style="color: {{ ($('Webhook — Recebe do Backend').item.json.resumo?.slaPct ?? 0) >= 80 ? '#16a34a' : '#ef4444' }};">{{ $('Webhook — Recebe do Backend').item.json.resumo?.slaPct ?? 0 }}%</div>
        <div class="kpi-label">SLA</div>
      </div>
    </div>

    <div class="kpis">
      <div class="kpi">
        <div class="kpi-valor" style="color: #f59e0b;">{{ $('Webhook — Recebe do Backend').item.json.resumo?.envelhecidos ?? 0 }}</div>
        <div class="kpi-label">+45 dias (envelhec.)</div>
      </div>
      <div class="kpi">
        <div class="kpi-valor" style="color: #3b82f6;">{{ $('Webhook — Recebe do Backend').item.json.resumo?.tempoMedioSolucao ?? 0 }}h</div>
        <div class="kpi-label">Tempo Médio Solução</div>
      </div>
      <div class="kpi">
        <div class="kpi-valor" style="color: #8b5cf6;">{{ $('Webhook — Recebe do Backend').item.json.resumo?.solucionadosPeriodo ?? 0 }}</div>
        <div class="kpi-label">Solucionados 30d</div>
      </div>
    </div>

    <!-- SLA bar -->
    <div class="section-title">SLA do Período</div>
    <div class="sla-bar">
      <div class="sla-fill" style="width: {{ $('Webhook — Recebe do Backend').item.json.resumo?.slaPct ?? 0 }}%; background: {{ ($('Webhook — Recebe do Backend').item.json.resumo?.slaPct ?? 0) >= 80 ? '#16a34a' : ($('Webhook — Recebe do Backend').item.json.resumo?.slaPct ?? 0) >= 60 ? '#f59e0b' : '#ef4444' }};"></div>
    </div>
    <p style="font-size: 12px; color: #64748b; margin: 4px 0 0; text-align: right;">{{ $('Webhook — Recebe do Backend').item.json.resumo?.slaPct ?? 0 }}% dentro do prazo</p>

    <!-- Top Atendentes -->
    {{ $('Webhook — Recebe do Backend').item.json.atendentesHoje?.length ? '<div class="section-title">🏆 Top Atendentes Hoje</div>' : '' }}
    {{ $('Webhook — Recebe do Backend').item.json.atendentesHoje?.map((a, i) => `<div class="atendente-row"><span class="atendente-nome">${i + 1}. ${a.nome}</span><span class="atendente-qtd">${a.resolvidos} ✓</span></div>`).join('') ?? '' }}

    <!-- Top Categorias -->
    {{ $('Webhook — Recebe do Backend').item.json.categoriasHoje?.length ? '<div class="section-title" style="margin-top: 20px;">📂 Categorias com Mais Chamados Hoje</div>' : '' }}
    {{ $('Webhook — Recebe do Backend').item.json.categoriasHoje?.map(c => `<div class="categoria-row"><span class="categoria-nome">${c.categoria}</span><span class="categoria-qtd">${c.qtd}</span></div>`).join('') ?? '' }}

  </div>

  <!-- Footer -->
  <div class="footer">
    Gerado automaticamente pelo Painel de Rotinas TI · John Deere<br>
    {{ $now.setLocale('pt').toFormat('dd/MM/yyyy HH:mm') }}
  </div>

</div>
</body>
</html>
